import{_ as a,c as r,o as e,a1 as o}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Устранение 429: ротация аккаунтов и обработка ошибок | Antigravity-Manager","description":"Научитесь методам устранения ошибки 429 в Antigravity Tools. Освойте распознавание и обработку ошибок QUOTA_EXHAUSTED, RATE_LIMIT_EXCEEDED и других. Быстро найдите проблему с помощью Monitor и X-Account-Email.","frontmatter":{"title":"Устранение 429: ротация аккаунтов и обработка ошибок | Antigravity-Manager","sidebarTitle":"Ошибка 429: автоматическая ротация аккаунтов","subtitle":"Устранение 429: ротация аккаунтов и обработка ошибок","description":"Научитесь методам устранения ошибки 429 в Antigravity Tools. Освойте распознавание и обработку ошибок QUOTA_EXHAUSTED, RATE_LIMIT_EXCEEDED и других. Быстро найдите проблему с помощью Monitor и X-Account-Email.","tags":["FAQ","Устранение неполадок","Планирование аккаунтов","Ошибка 429"],"prerequisite":["start-getting-started","advanced-scheduling"],"order":3},"headers":[],"relativePath":"ru/lbjlaq/Antigravity-Manager/faq/429-rotation/index.md","filePath":"ru/lbjlaq/Antigravity-Manager/faq/429-rotation/index.md"}'),i={name:"ru/lbjlaq/Antigravity-Manager/faq/429-rotation/index.md"};function s(l,t,n,d,c,p){return e(),r("div",null,[...t[0]||(t[0]=[o(`<h1 id="_429-ошибка-емкости-правильные-ожидания-ротации-аккаунтов-и-заблуждения-об-исчерпании-емкости-модели" tabindex="-1">429/Ошибка емкости: правильные ожидания ротации аккаунтов и заблуждения об исчерпании емкости модели <a class="header-anchor" href="#_429-ошибка-емкости-правильные-ожидания-ротации-аккаунтов-и-заблуждения-об-исчерпании-емкости-модели" aria-label="Permalink to &quot;429/Ошибка емкости: правильные ожидания ротации аккаунтов и заблуждения об исчерпании емкости модели&quot;">​</a></h1><h2 id="чему-вы-научитесь" tabindex="-1">Чему вы научитесь <a class="header-anchor" href="#чему-вы-научитесь" aria-label="Permalink to &quot;Чему вы научитесь&quot;">​</a></h2><ul><li>Правильно различать &quot;недостаток квоты&quot; и &quot;ограничение скорости апстрима&quot;</li><li>Понять механизм автоматической ротации Antigravity Tools и ожидаемое поведение</li><li>При возникновении ошибки 429 знать, как быстро найти проблему и оптимизировать конфигурацию</li></ul><h2 id="ваша-текущая-проблема" tabindex="-1">Ваша текущая проблема <a class="header-anchor" href="#ваша-текущая-проблема" aria-label="Permalink to &quot;Ваша текущая проблема&quot;">​</a></h2><ul><li>Видите ошибку 429, думаете, что &quot;у модели нет емкости&quot;</li><li>Настроили несколько аккаунтов, но все равно часто сталкиваетесь с 429, не знаете, это проблема конфигурации или аккаунта</li><li>Не понятно, когда система автоматически переключит аккаунт, а когда &quot;застрянет&quot;</li></ul><h2 id="основная-идея" tabindex="-1">Основная идея <a class="header-anchor" href="#основная-идея" aria-label="Permalink to &quot;Основная идея&quot;">​</a></h2><h3 id="что-такое-ошибка-429" tabindex="-1">Что такое ошибка 429? <a class="header-anchor" href="#что-такое-ошибка-429" aria-label="Permalink to &quot;Что такое ошибка 429?&quot;">​</a></h3><p><strong>429 Too Many Requests</strong> - это код состояния HTTP. В Antigravity Tools ошибка 429 означает не только &quot;слишком много запросов&quot;, но и ряд сигналов &quot;вы временно не можете использовать&quot;, таких как исчерпание квоты, временная перегрузка модели и т.д.</p><div class="info custom-block"><p class="custom-block-title">Прокси пытается определить причину 429</p><p>Прокси пытается разобрать <code>error.details[0].reason</code> или <code>error.message</code> из тела ответа, грубо разделяя 429 на несколько типов (фактически зависит от возвращаемого значения):</p><table tabindex="0"><thead><tr><th>Тип, определяемый прокси</th><th>Распространенная reason / подсказка</th><th>Типичная характеристика</th></tr></thead><tbody><tr><td><strong>Исчерпание квоты</strong></td><td><code>QUOTA_EXHAUSTED</code> / текст содержит <code>exhausted</code>, <code>quota</code></td><td>Возможно, нужно дождаться обновления квоты</td></tr><tr><td><strong>Ограничение скорости</strong></td><td><code>RATE_LIMIT_EXCEEDED</code> / текст содержит <code>per minute</code>, <code>rate limit</code>, <code>too many requests</code></td><td>Обычно период охлаждения в десятки секунд</td></tr><tr><td><strong>Недостаток емкости модели</strong></td><td><code>MODEL_CAPACITY_EXHAUSTED</code> / текст содержит <code>model_capacity</code></td><td>Обычно кратковременная перегрузка, позже можно восстановить</td></tr><tr><td><strong>Неизвестно</strong></td><td>Не удалось разобрать</td><td>Используется стратегия охлаждения по умолчанию</td></tr></tbody></table></div><h3 id="автоматическая-обработка-в-antigravity-tools" tabindex="-1">Автоматическая обработка в Antigravity Tools <a class="header-anchor" href="#автоматическая-обработка-в-antigravity-tools" aria-label="Permalink to &quot;Автоматическая обработка в Antigravity Tools&quot;">​</a></h3><p>Когда запрос сталкивается с 429 (а также с некоторыми 5xx/перегрузками), прокси обычно делает две вещи на стороне сервера:</p><ol><li><strong>Записать время охлаждения</strong>: Записать эту ошибку в <code>RateLimitTracker</code>, при последующем выборе аккаунта будет активно избегать аккаунтов, которые &quot;все еще охлаждаются&quot;.</li><li><strong>Ротация аккаунтов при повторной попытке</strong>: Handlers будут делать несколько попыток в рамках одного запроса, при повторной попытке <code>force_rotate=true</code>, тем самым запуская TokenManager выбрать следующий доступный аккаунт.</li></ol><div class="tip custom-block"><p class="custom-block-title">Как узнать, переключился ли аккаунт?</p><p>Даже если тело вашего запроса не изменилось, в ответе обычно есть <code>X-Account-Email</code> (и <code>X-Mapped-Model</code>), вы можете использовать его для проверки &quot;какой аккаунт использовался в этом запросе&quot;.</p></div><h2 id="когда-возникает-ошибка-429" tabindex="-1">Когда возникает ошибка 429? <a class="header-anchor" href="#когда-возникает-ошибка-429" aria-label="Permalink to &quot;Когда возникает ошибка 429?&quot;">​</a></h2><h3 id="сценарии-1-слишком-частые-запросы-одного-аккаунта" tabindex="-1">Сценарий 1: Слишком частые запросы одного аккаунта <a class="header-anchor" href="#сценарии-1-слишком-частые-запросы-одного-аккаунта" aria-label="Permalink to &quot;Сценарий 1: Слишком частые запросы одного аккаунта&quot;">​</a></h3><p><strong>Симптом</strong>: Даже с одним аккаунтом отправка большого количества запросов за короткое время вызывает 429.</p><p><strong>Причина</strong>: У каждого аккаунта есть собственное ограничение скорости (RPM/TPM), превышение приведет к ограничению.</p><p><strong>Решение</strong>:</p><ul><li>Увеличить количество аккаунтов</li><li>Снизить частоту запросов</li><li>Использовать режим фиксированного аккаунта для распределения нагрузки (см. &quot;Режим фиксированного аккаунта&quot;)</li></ul><h3 id="сценарии-2-одновременное-ограничение-всех-аккаунтов" tabindex="-1">Сценарий 2: Одновременное ограничение всех аккаунтов <a class="header-anchor" href="#сценарии-2-одновременное-ограничение-всех-аккаунтов" aria-label="Permalink to &quot;Сценарий 2: Одновременное ограничение всех аккаунтов&quot;">​</a></h3><p><strong>Симптом</strong>: Есть несколько аккаунтов, но все возвращают 429.</p><p><strong>Причина</strong>:</p><ul><li>Общее количество аккаунтов недостаточно для вашей частоты запросов</li><li>Почти все аккаунты одновременно вызывают ограничение/перегрузку</li></ul><p><strong>Решение</strong>:</p><ul><li>Добавить больше аккаунтов</li><li>Изменить режим планирования на &quot;Приоритет производительности&quot; (пропустить липкие сессии и повторное использование окна 60s)</li><li>Проверить, не исключает ли защита квоты доступные аккаунты</li></ul><h3 id="сценарии-3-аккаунт-ошибочно-помечен-защитои-квоты" tabindex="-1">Сценарий 3: Аккаунт ошибочно помечен защитой квоты <a class="header-anchor" href="#сценарии-3-аккаунт-ошибочно-помечен-защитои-квоты" aria-label="Permalink to &quot;Сценарий 3: Аккаунт ошибочно помечен защитой квоты&quot;">​</a></h3><p><strong>Симптом</strong>: Квота определенного аккаунта достаточна, но система постоянно пропускает его.</p><p><strong>Причина</strong>:</p><ul><li>Включена <strong>защита квоты</strong>, порог установлен слишком высоко</li><li>Квота определенной модели этого аккаунта ниже порога</li><li>Аккаунт вручную помечен как <code>proxy_disabled</code></li></ul><p><strong>Решение</strong>:</p><ul><li>Проверьте настройки защиты квоты (Settings → Quota Protection), настройте порог и модели мониторинга в соответствии с интенсивностью использования</li><li>В данных аккаунта проверьте <code>protected_models</code>, убедитесь, что он не пропущен политикой защиты</li></ul><h2 id="делаите-вместе-со-мнои" tabindex="-1">Делайте вместе со мной <a class="header-anchor" href="#делаите-вместе-со-мнои" aria-label="Permalink to &quot;Делайте вместе со мной&quot;">​</a></h2><h3 id="шаг-1-определите-тип-ошибки-429" tabindex="-1">Шаг 1: Определите тип ошибки 429 <a class="header-anchor" href="#шаг-1-определите-тип-ошибки-429" aria-label="Permalink to &quot;Шаг 1: Определите тип ошибки 429&quot;">​</a></h3><p><strong>Зачем</strong>: Различные типы ошибок 429 требуют разной обработки.</p><p>В Proxy Monitor посмотрите тело ответа ошибки 429, сосредоточьтесь на двух типах информации:</p><ul><li><strong>Причина</strong>: <code>error.details[0].reason</code> (например, <code>RATE_LIMIT_EXCEEDED</code>, <code>QUOTA_EXHAUSTED</code>) или <code>error.message</code></li><li><strong>Время ожидания</strong>: <code>RetryInfo.retryDelay</code> или <code>details[0].metadata.quotaResetDelay</code> (если существует)</li></ul><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;error&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;details&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">        &quot;reason&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;RATE_LIMIT_EXCEEDED&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">        &quot;metadata&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">          &quot;quotaResetDelay&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;42s&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>Вы должны увидеть</strong>:</p><ul><li>Если в теле ответа можно найти время ожидания (например, <code>RetryInfo.retryDelay</code> или <code>quotaResetDelay</code>), прокси обычно сначала подождет короткое время, затем повторит попытку.</li><li>Если времени ожидания нет, прокси добавит &quot;период охлаждения&quot; для этого аккаунта в соответствии со встроенной стратегией и при повторной попытке сразу перейдет к следующему аккаунту.</li></ul><h3 id="шаг-2-проверьте-конфигурацию-планирования-аккаунтов" tabindex="-1">Шаг 2: Проверьте конфигурацию планирования аккаунтов <a class="header-anchor" href="#шаг-2-проверьте-конфигурацию-планирования-аккаунтов" aria-label="Permalink to &quot;Шаг 2: Проверьте конфигурацию планирования аккаунтов&quot;">​</a></h3><p><strong>Зачем</strong>: Конфигурация планирования напрямую влияет на частоту ротации аккаунтов и приоритет.</p><p>Перейдите на страницу <strong>API Proxy</strong>, посмотрите стратегию планирования:</p><table tabindex="0"><thead><tr><th>Элемент конфигурации</th><th>Описание</th><th>Значение по умолчанию / рекомендация</th></tr></thead><tbody><tr><td><strong>Scheduling Mode</strong></td><td>Режим планирования</td><td><code>Balance</code> (по умолчанию)</td></tr><tr><td><strong>Preferred Account</strong></td><td>Режим фиксированного аккаунта</td><td>Не выбрано (по умолчанию)</td></tr></tbody></table><p><strong>Сравнение режимов планирования</strong>:</p><table tabindex="0"><thead><tr><th>Режим</th><th>Стратегия повторного использования аккаунтов</th><th>Обработка ограничения скорости</th><th>Применимые сценарии</th></tr></thead><tbody><tr><td><strong>CacheFirst</strong></td><td>Включает липкие сессии и повторное использование окна 60s</td><td><strong>Приоритет ожидания</strong>, значительно повышает коэффициент попадания Prompt Caching</td><td>Диалоговые / требующие высокого коэффициента попадания кэша</td></tr><tr><td><strong>Balance</strong></td><td>Включает липкие сессии и повторное использование окна 60s</td><td><strong>Сразу переключается</strong> на альтернативный аккаунт, учитывая как успешность, так и производительность</td><td>Универсальный сценарий, по умолчанию</td></tr><tr><td><strong>PerformanceFirst</strong></td><td>Пропускает липкие сессии и повторное использование окна 60s, чистый режим round-robin</td><td>Сразу переключается, нагрузка на аккаунты наиболее равномерная</td><td>Высокая параллельность, бес状態ные запросы</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Кэш-приоритет против балансового режима</p><p>Если вы используете Prompt Caching и хотите повысить коэффициент попадания кэша, выберите <code>CacheFirst</code> - при ограничении скорости он будет преимущественно ждать, а не сразу переключать аккаунт. Если вы больше цените успешность запроса, чем кэш, выберите <code>Balance</code> - при ограничении скорости он сразу переключит аккаунт.</p></div><div class="tip custom-block"><p class="custom-block-title">Режим приоритета производительности</p><p>Если ваши запросы бес状態ные (например, генерация изображений, отдельные запросы), попробуйте <code>PerformanceFirst</code>. Он пропускает липкие сессии и повторное использование окна 60s, позволяя последовательным запросам легче попадать на разные аккаунты.</p></div><h3 id="шаг-3-проверьте-нормально-ли-работает-ротация-аккаунтов" tabindex="-1">Шаг 3: Проверьте, нормально ли работает ротация аккаунтов <a class="header-anchor" href="#шаг-3-проверьте-нормально-ли-работает-ротация-аккаунтов" aria-label="Permalink to &quot;Шаг 3: Проверьте, нормально ли работает ротация аккаунтов&quot;">​</a></h3><p><strong>Зачем</strong>: Убедитесь, что система может автоматически переключать аккаунты.</p><p><strong>Метод 1: Смотрите заголовки ответа</strong></p><p>С помощью curl или своего клиента выведите заголовки ответа и посмотрите, меняется ли <code>X-Account-Email</code>.</p><p><strong>Метод 2: Просмотрите логи</strong></p><p>Откройте файл логов (в зависимости от вашей системы), найдите <code>🔄 [Token Rotation]</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>🔄 [Token Rotation] Accounts: [</span></span>
<span class="line"><span>  &quot;account1@example.com(protected=[])&quot;,</span></span>
<span class="line"><span>  &quot;account2@example.com(protected=[])&quot;,</span></span>
<span class="line"><span>  &quot;account3@example.com(protected=[])&quot;</span></span>
<span class="line"><span>]</span></span></code></pre></div><p><strong>Метод 3: Используйте Proxy Monitor</strong></p><p>На странице <strong>Monitor</strong> просмотрите логи запросов, обратите внимание на:</p><ul><li>Меняется ли поле <strong>Account</strong> между разными аккаунтами</li><li>После запросов со статусом <strong>429</strong>, есть ли успешные запросы, использующие разные аккаунты</li></ul><p><strong>Вы должны увидеть</strong>:</p><ul><li>После того, как определенный аккаунт возвращает 429, последующие запросы автоматически переключаются на другие аккаунты</li><li>Если несколько запросов используют один и тот же аккаунт и все неудачны, возможно, проблема с конфигурацией планирования</li></ul><h3 id="шаг-4-оптимизируите-приоритет-аккаунтов" tabindex="-1">Шаг 4: Оптимизируйте приоритет аккаунтов <a class="header-anchor" href="#шаг-4-оптимизируите-приоритет-аккаунтов" aria-label="Permalink to &quot;Шаг 4: Оптимизируйте приоритет аккаунтов&quot;">​</a></h3><p><strong>Зачем</strong>: Пусть система сначала использует аккаунты с высокой квотой/высоким уровнем, снижая вероятность 429.</p><p>В TokenManager система отсортирует пул аккаунтов перед выбором аккаунта (выведет <code>🔄 [Token Rotation] Accounts: ...</code>):</p><ol><li><strong>Приоритет уровня подписки</strong>: ULTRA &gt; PRO &gt; FREE</li><li><strong>Приоритет процента квоты</strong>: В пределах одного уровня, аккаунты с более высокой квотой идут первыми</li><li><strong>Точка входа сортировки</strong>: Эта сортировка происходит на стороне прокси, окончательный выбор аккаунта зависит от сортировки + оценки доступности на стороне прокси.</li></ol><div class="info custom-block"><p class="custom-block-title">Принцип умной сортировки (на стороне прокси)</p><p>Приоритет: <code>ULTRA &gt; PRO &gt; FREE</code>; В пределах одного уровня подписки по убыванию <code>remaining_quota</code> (максимальный процент оставшейся квоты аккаунта).</p></div><p><strong>Действия</strong>:</p><ul><li>Перетащите аккаунты для настройки порядка отображения (опционально)</li><li>Обновите квоту (Accounts → Обновить все квоты)</li><li>Проверьте уровень подписки и квоту аккаунтов</li></ul><h2 id="предупреждения-о-типичных-ошибках" tabindex="-1">Предупреждения о типичных ошибках <a class="header-anchor" href="#предупреждения-о-типичных-ошибках" aria-label="Permalink to &quot;Предупреждения о типичных ошибках&quot;">​</a></h2><h3 id="❌-ошибка-1-неправильное-понимание-429-как-у-модели-нет-емкости" tabindex="-1">❌ Ошибка 1: Неправильное понимание 429 как &quot;у модели нет емкости&quot; <a class="header-anchor" href="#❌-ошибка-1-неправильное-понимание-429-как-у-модели-нет-емкости" aria-label="Permalink to &quot;❌ Ошибка 1: Неправильное понимание 429 как &quot;у модели нет емкости&quot;&quot;">​</a></h3><p><strong>Симптом</strong>: При виде ошибки 429 думаешь, что у модели нет емкости.</p><p><strong>Правильное понимание</strong>:</p><ul><li>429 - это <strong>ограничение скорости</strong>, а не проблема емкости</li><li>Добавление аккаунтов может снизить вероятность 429</li><li>Изменение режима планирования может ускорить переключение</li></ul><h3 id="❌-ошибка-2-порог-защиты-квоты-установлен-слишком-высоко" tabindex="-1">❌ Ошибка 2: Порог защиты квоты установлен слишком высоко <a class="header-anchor" href="#❌-ошибка-2-порог-защиты-квоты-установлен-слишком-высоко" aria-label="Permalink to &quot;❌ Ошибка 2: Порог защиты квоты установлен слишком высоко&quot;">​</a></h3><p><strong>Симптом</strong>: Квота достаточна, но система постоянно пропускает аккаунты.</p><p><strong>Причина</strong>: Защита квоты добавит модели ниже порога в <code>protected_models</code> аккаунта, прокси при планировании пропустит &quot;защищенные модели&quot;. При слишком высоком пороге доступные аккаунты могут быть чрезмерно исключены.</p><p><strong>Исправление</strong>:</p><ul><li>Вернитесь в <strong>Settings → Quota Protection</strong>, настройте модели мониторинга и пороги</li><li>Если вы хотите точно знать, какие модели защищены, посмотрите <code>protected_models</code> в данных аккаунтов</li></ul><h3 id="❌-ошибка-3-режим-фиксированного-аккаунта-блокирует-ротацию" tabindex="-1">❌ Ошибка 3: Режим фиксированного аккаунта блокирует ротацию <a class="header-anchor" href="#❌-ошибка-3-режим-фиксированного-аккаунта-блокирует-ротацию" aria-label="Permalink to &quot;❌ Ошибка 3: Режим фиксированного аккаунта блокирует ротацию&quot;">​</a></h3><p><strong>Симптом</strong>: Установлен <code>Preferred Account</code>, но после ограничения скорости этого аккаунта система &quot;застряла&quot;.</p><p><strong>Причина</strong>: В режиме фиксированного аккаунта система сначала использует указанный аккаунт, только когда аккаунт недоступен, понижается до round-robin.</p><p><strong>Исправление</strong>:</p><ul><li>Если вам не нужен фиксированный аккаунт, очистите <code>Preferred Account</code></li><li>Или убедитесь, что квота фиксированного аккаунта достаточна, избегайте ограничения скорости</li></ul><h2 id="контрольная-точка-✅" tabindex="-1">Контрольная точка ✅ <a class="header-anchor" href="#контрольная-точка-✅" aria-label="Permalink to &quot;Контрольная точка ✅&quot;">​</a></h2><ul><li>[ ] Можете различить исчерпание квоты и ограничение скорости апстрима</li><li>[ ] Знаете, как просмотреть детали ошибки 429 в Proxy Monitor</li><li>[ ] Понимаете разницу между тремя режимами планирования и сценариями использования</li><li>[ ] Знаете, как проверить, нормально ли работает ротация аккаунтов</li><li>[ ] Можете оптимизировать приоритет аккаунтов и проверить стратегию защиты квоты</li></ul><h2 id="частые-вопросы" tabindex="-1">Частые вопросы <a class="header-anchor" href="#частые-вопросы" aria-label="Permalink to &quot;Частые вопросы&quot;">​</a></h2><h3 id="вопрос-1-почему-у-меня-несколько-аккаунтов-но-все-равно-возникает-429" tabindex="-1">Вопрос 1: Почему у меня несколько аккаунтов, но все равно возникает 429? <a class="header-anchor" href="#вопрос-1-почему-у-меня-несколько-аккаунтов-но-все-равно-возникает-429" aria-label="Permalink to &quot;Вопрос 1: Почему у меня несколько аккаунтов, но все равно возникает 429?&quot;">​</a></h3><p>A: Возможные причины:</p><ol><li>Все аккаунты одновременно вызывают ограничение скорости (слишком высокая частота запросов)</li><li>Последовательные запросы в режиме &quot;повторного использования окна 60s&quot; многократно используют один и тот же аккаунт, проще довести один аккаунт до ограничения скорости</li><li>Защита квоты ошибочно исключает доступные аккаунты</li><li>Общее количество аккаунтов недостаточно для вашей частоты запросов</li></ol><p><strong>Решение</strong>:</p><ul><li>Добавьте больше аккаунтов</li><li>Используйте режим <code>PerformanceFirst</code></li><li>Проверьте, добавила ли Quota Protection используемые вами модели в <code>protected_models</code> (при необходимости настройте модели мониторинга и пороги)</li><li>Снизьте частоту запросов</li></ul><h3 id="вопрос-2-будет-ли-ошибка-429-автоматически-повторена" tabindex="-1">Вопрос 2: Будет ли ошибка 429 автоматически повторена? <a class="header-anchor" href="#вопрос-2-будет-ли-ошибка-429-автоматически-повторена" aria-label="Permalink to &quot;Вопрос 2: Будет ли ошибка 429 автоматически повторена?&quot;">​</a></h3><p>A: Она будет автоматически повторена в рамках одного запроса. <strong>Максимальное количество повторных попыток обычно 3</strong>, конкретный метод расчета: <code>min(3, размер пула аккаунтов)</code>, и минимум 1 попытка.</p><p><strong>Пример количества повторных попыток</strong>:</p><ul><li>Пул аккаунтов с 1 аккаунтом → 1 попытка (без повторной попытки)</li><li>Пул аккаунтов с 2 аккаунтами → 2 попытки (1 повторная попытка)</li><li>Пул аккаунтов с 3 или более аккаунтами → 3 попытки (2 повторные попытки)</li></ul><p><strong>Общий процесс</strong>:</p><ol><li>Записать информацию об ограничении скорости/перегрузке (попасть в <code>RateLimitTracker</code>)</li><li>Если можно разобрать время ожидания (например, <code>RetryInfo.retryDelay</code> / <code>quotaResetDelay</code>), сначала подождет короткое время, затем продолжит</li><li>При повторной попытке принудительно ротировать аккаунты (когда <code>attempt &gt; 0</code>, <code>force_rotate=true</code>), попробовать использовать следующий доступный аккаунт для отправки запроса апстриму</li></ol><p>Если все попытки неудачны, прокси вернет ошибку клиенту; в то же время вы все равно можете увидеть фактически использованные аккаунты из заголовков ответа (например, <code>X-Account-Email</code>) или Proxy Monitor.</p><h3 id="вопрос-3-как-просмотреть-как-долго-аккаунт-ограничен" tabindex="-1">Вопрос 3: Как просмотреть, как долго аккаунт ограничен? <a class="header-anchor" href="#вопрос-3-как-просмотреть-как-долго-аккаунт-ограничен" aria-label="Permalink to &quot;Вопрос 3: Как просмотреть, как долго аккаунт ограничен?&quot;">​</a></h3><p>A: Есть два способа:</p><p><strong>Способ 1</strong>: Просмотрите логи, найдите <code>rate-limited</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>🔒 [FIX #820] Preferred account xxx@gmail.com is rate-limited, falling back to round-robin</span></span></code></pre></div><p><strong>Способ 2</strong>: В логах будет показано оставшееся время ожидания</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>All accounts are currently limited. Please wait 30s.</span></span></code></pre></div><h3 id="вопрос-4-защита-квоты-и-ограничение-скорости-это-одно-и-то-же" tabindex="-1">Вопрос 4: Защита квоты и ограничение скорости - это одно и то же? <a class="header-anchor" href="#вопрос-4-защита-квоты-и-ограничение-скорости-это-одно-и-то-же" aria-label="Permalink to &quot;Вопрос 4: Защита квоты и ограничение скорости - это одно и то же?&quot;">​</a></h3><p>A: Нет.</p><table tabindex="0"><thead><tr><th>Характеристика</th><th>Защита квоты</th><th>Отслеживание ограничения скорости</th></tr></thead><tbody><tr><td><strong>Условие срабатывания</strong></td><td>Квота модели ниже порога</td><td>Получена ошибка 429</td></tr><tr><td><strong>Область действия</strong></td><td>Определенные модели</td><td>Весь аккаунт</td></tr><tr><td><strong>Продолжительность</strong></td><td>До восстановления квоты</td><td>Решает апстрим (обычно несколько секунд до нескольких минут)</td></tr><tr><td><strong>Поведение</strong></td><td>Пропустить эту модель</td><td>Пропустить этот аккаунт</td></tr></tbody></table><h3 id="вопрос-5-как-принудительно-сразу-переключить-аккаунт" tabindex="-1">Вопрос 5: Как принудительно сразу переключить аккаунт? <a class="header-anchor" href="#вопрос-5-как-принудительно-сразу-переключить-аккаунт" aria-label="Permalink to &quot;Вопрос 5: Как принудительно сразу переключить аккаунт?&quot;">​</a></h3><p>A: Можно подойти с точки зрения &quot;сделать следующий запрос легче переключить аккаунт&quot;:</p><ol><li><strong>На уровне планирования</strong>: переключитесь на <code>PerformanceFirst</code>, пропустите липкие сессии и повторное использование окна 60s</li><li><strong>Фиксированный аккаунт</strong>: если включен <code>Preferred Account</code>, сначала очистите его, иначе будет преимущественно использовать фиксированный аккаунт (пока он не ограничен/защищен)</li><li><strong>Пул аккаунтов</strong>: увеличьте количество аккаунтов, при ограничении одного аккаунта проще найти альтернативный аккаунт</li></ol><p>В рамках одного запроса прокси сам принудительно ротирует при повторной попытке (<code>attempt &gt; 0</code> вызовет <code>force_rotate=true</code>), но количество повторных попыток ограничено.</p><h2 id="краткии-итог-урока" tabindex="-1">Краткий итог урока <a class="header-anchor" href="#краткии-итог-урока" aria-label="Permalink to &quot;Краткий итог урока&quot;">​</a></h2><ul><li>429 в Antigravity Tools - это сигнал &quot;апстрим временно недоступен&quot;, может быть ограничением скорости, исчерпанием квоты, недостатком емкости модели и т.д.</li><li>Прокси записывает время охлаждения и пытается ротировать аккаунты при повторной попытке в рамках одного запроса (но количество повторных попыток ограничено)</li><li>Режим планирования, Quota Protection, количество аккаунтов влияют на вероятность возникновения 429 и скорость восстановления</li><li>С помощью Proxy Monitor, заголовков ответа <code>X-Account-Email</code> и логов можно быстро найти проблему</li></ul><h2 id="следующии-урок预告" tabindex="-1">Следующий урок预告 <a class="header-anchor" href="#следующии-урок预告" aria-label="Permalink to &quot;Следующий урок预告&quot;">​</a></h2><blockquote><p>Следующий урок мы изучим <strong><a href="./../404-base-url/">404/Несовместимость путей: Base URL, префикс /v1 и клиенты с &quot;дублирующимися путями&quot;</a></strong>.</p><p>Вы узнаете:</p><ul><li>Как возникает самая распространенная ошибка интеграции (404)</li><li>Различия в конкатенации base_url у разных клиентов</li><li>Как быстро исправить проблему 404</li></ul></blockquote><hr><h2 id="приложение-справка-по-исходному-коду" tabindex="-1">Приложение: Справка по исходному коду <a class="header-anchor" href="#приложение-справка-по-исходному-коду" aria-label="Permalink to &quot;Приложение: Справка по исходному коду&quot;">​</a></h2><details><summary><strong>Нажмите, чтобы увидеть местоположение исходного кода</strong></summary><blockquote><p>Обновлено: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Функция</th><th>Путь к файлу</th><th>Строки</th></tr></thead><tbody><tr><td>Разбор задержки повтора 429 (RetryInfo / quotaResetDelay)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/upstream/retry.rs#L38-L67" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/upstream/retry.rs</code></a></td><td>38-67</td></tr><tr><td>Инструмент разбора Duration</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/upstream/retry.rs#L11-L35" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/upstream/retry.rs</code></a></td><td>11-35</td></tr><tr><td>Перечисление режимов планирования (CacheFirst/Balance/PerformanceFirst)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/sticky_config.rs#L3-L12" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/sticky_config.rs</code></a></td><td>3-12</td></tr><tr><td>Разбор причины ограничения скорости и стратегия охлаждения по умолчанию</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/rate_limit.rs#L5-L258" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/rate_limit.rs</code></a></td><td>5-258</td></tr><tr><td>Определение константы MAX_RETRY_ATTEMPTS (OpenAI handler)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/openai.rs#L14" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/openai.rs</code></a></td><td>14</td></tr><tr><td>Расчет количества повторных попыток (max_attempts = min(MAX_RETRY_ATTEMPTS, pool_size))</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/openai.rs#L830" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/openai.rs</code></a></td><td>830</td></tr><tr><td>OpenAI handler: при 429/5xx отметить ограничение скорости и повторить/ротировать</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/openai.rs#L349-L389" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/openai.rs</code></a></td><td>349-389</td></tr><tr><td>Приоритет сортировки аккаунтов (ULTRA &gt; PRO &gt; FREE + remaining_quota)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L504-L538" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>504-538</td></tr><tr><td>Повторное использование окна 60s + избегание ограничения скорости/защиты квоты</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L624-L739" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>624-739</td></tr><tr><td>Точка входа записи ограничения скорости (mark_rate_limited)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L1089-L1113" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>1089-1113</td></tr><tr><td>Точное блокирование 429 / обновление квоты в реальном времени / стратегия понижения (mark_rate_limited_async)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L1258-L1417" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>1258-1417</td></tr></tbody></table><p><strong>Ключевые константы</strong>:</p><ul><li><code>MAX_RETRY_ATTEMPTS = 3</code>: Максимальное количество повторных попыток в рамках одного запроса (OpenAI/Gemini handler)</li><li><code>60</code>: Повторное использование окна 60s (включается только в режимах, отличных от <code>PerformanceFirst</code>)</li><li><code>5</code>: Время ожидания получения токена (секунды)</li><li><code>300</code>: Порог раннего обновления токена (секунды, 5 минут)</li></ul><p><strong>Ключевые функции</strong>:</p><ul><li><code>parse_retry_delay()</code>: Извлечение задержки повтора из ответа об ошибке 429</li><li><code>get_token_internal()</code>: Основная логика выбора и ротации аккаунтов</li><li><code>mark_rate_limited()</code>: Пометить аккаунт как состояние ограничения скорости</li></ul></details>`,116)])])}const g=a(i,[["render",s]]);export{u as __pageData,g as default};
